#include <stdio.h>
#include <stdint.h>
#include <string.h>

#define MAXN 100
#define WORDS 2   // we use two 64‑bit words to cover up to 128 vertices

static uint64_t adj[MAXN][WORDS]; // complement adjacency (non‑overlap)
static int n;
static int best;

static inline int popcount_set(uint64_t a, uint64_t b){
    return __builtin_popcountll(a) + __builtin_popcountll(b);
}

static void dfs(uint64_t cand0, uint64_t cand1, int cur){
    int possible = popcount_set(cand0, cand1);
    if (cur + possible <= best) return; // prune
    while (cand0 || cand1){
        int v;
        if (cand0){
            v = __builtin_ctzll(cand0);
            cand0 &= ~(1ULL<<v);
        }else{
            v = 64 + __builtin_ctzll(cand1);
            cand1 &= ~(1ULL<<(v-64));
        }
        // intersect remaining candidates with neighbours of v
        uint64_t new0 = cand0 & adj[v][0];
        uint64_t new1 = cand1 & adj[v][1];
        dfs(new0, new1, cur+1);
        // after returning, continue with the reduced candidate set (v already removed)
        possible = popcount_set(cand0, cand1);
        if (cur + possible <= best) return; // additional prune
    }
    if (cur > best) best = cur;
}

int main(){
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--){
        if (scanf("%d", &n)!=1) return 0;
        int x0[MAXN], y0[MAXN], x1[MAXN], y1[MAXN];
        for (int i=0;i<n;i++){
            scanf("%d %d %d %d", &x0[i], &y0[i], &x1[i], &y1[i]);
        }
        // build complement adjacency (non‑overlap)
        memset(adj, 0, sizeof(adj));
        for (int i=0;i<n;i++){
            for (int j=i+1;j<n;j++){
                int overlap = !(x1[i] <= x0[j] || x1[j] <= x0[i] || y1[i] <= y0[j] || y1[j] <= y0[i]);
                if (!overlap){ // they do NOT overlap -> edge in complement graph
                    if (j < 64) adj[i][0] |= 1ULL<<j; else adj[i][1] |= 1ULL<<(j-64);
                    if (i < 64) adj[j][0] |= 1ULL<<i; else adj[j][1] |= 1ULL<<(i-64);
                }
            }
        }
        // initial candidate set: all vertices
        uint64_t cand0 = 0, cand1 = 0;
        for (int i=0;i<n;i++){
            if (i < 64) cand0 |= 1ULL<<i; else cand1 |= 1ULL<<(i-64);
        }
        best = 0;
        dfs(cand0, cand1, 0);
        printf("%d\n", best);
    }
    return 0;
}
